#include<bits/stdc++.h>
using namespace std;
long long f[2000010],g[2000010];
char s[2000010];
int lst[101];
int main()
{
    long long n;
    scanf("%lld%s",&n,s+1);
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        g[i]=i-1;
        while(g[i]>0&&s[i]!=s[g[i]])
        {
            g[i]=g[g[i]]-1;
        }
        if(g[i]>0)
        {
            f[i]=f[g[i]-1]+1;
        }
        ans+=f[i];
    }
    printf("%lld",ans);
    return 0;
}
